import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class SpeedIndicator extends StatelessWidget { final double? speedMs; const SpeedIndicator({super.key, this.speedMs}); @override Widget build(BuildContext context) { if (speedMs == null || speedMs! <= 0) return const SizedBox.shrink(); final kmh = speedMs! * 3.6; return Container(padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6), decoration: BoxDecoration(color: AppTheme.darkCard, borderRadius: BorderRadius.circular(8)), child: Row(mainAxisSize: MainAxisSize.min, children: [const Icon(Icons.speed, color: AppTheme.primaryColor, size: 16), const SizedBox(width: 4), Text('${kmh.toStringAsFixed(1)} km/h', style: const TextStyle(color: AppTheme.darkText, fontSize: 12, fontWeight: FontWeight.w600))])); } }